// ==================== COMBAT LOGS (MODULE) ====================
// 统一战斗日志规范：
// - 主动技能：显示“使用”
// - 被动触发（天赋/被动）：显示“【xxx】触发：...”，不算一次行动
// - 系统事件：显示纯文本
function normalizeCombatLogEntry(entry) {
    if (!entry || typeof entry !== 'object') {
        return { kind: 'system', text: String(entry ?? '') };
    }
    if (entry.kind) return entry;

    // 兼容旧字段：type
    if (entry.type === 'talent') {
        return { ...entry, kind: 'proc', proc: entry.action || entry.proc || '被动' };
    }
    if (entry.type === 'damage' || entry.type === 'heal' || entry.type === 'buff' || entry.type === 'block') {
        return { ...entry, kind: 'skill' };
    }
    return { ...entry, kind: 'system', text: entry.text || entry.action || '' };
}

function renderCombatLogLine(entry) {
    const e = normalizeCombatLogEntry(entry);

    // 系统日志
    if (e.kind === 'system') {
        return (
            <>
                <span style={{ color: '#aaa' }}>{e.text || ''}</span>
            </>
        );
    }

    // ✅ 新增：掉落日志
    if (e.kind === 'drop') {
        const rarityColors = {
            white: '#d9d9d9',
            green: '#1eff00',
            blue: '#0070dd',
            purple: '#a335ee',
            orange: '#ff8000'
        };
        const color = rarityColors[e.rarity] || '#ffd700';

        return (
            <>
                <span style={{ color: '#ffd700' }}>🎁 掉落</span>
                {' '}
                <span style={{
                    color: color,
                    fontWeight: 600,
                    textShadow: `0 0 6px ${color}66`
                }}>
                    【{e.itemName}】
                </span>
                <span style={{ color: '#888', marginLeft: 8, fontSize: '0.9em' }}>
                    概率：{e.chance < 1 ? e.chance.toFixed(2) : e.chance.toFixed(1)}%
                </span>
            </>
        );
    }

    // 被动触发：不显示“使用”，也不重复显示施放者（统一由文本自身表达）
    if (e.kind === 'proc') {
        return (
            <>
                <span style={{ color: '#ff9800' }}>
                    {e.text || `【${e.proc || e.action || '被动'}】触发`}
                </span>
            </>
        );
    }

// 主动技能：保留原来的“使用”语义
    return (
        <>
            <span style={{ color: '#ffd700' }}>{e.actor}</span>
            {' '}使用{' '}
            <span style={{ color: '#4CAF50' }}>{e.action}</span>

            {e.type === 'damage' && (
                <>
                    {' '}对{' '}
                    <span style={{ color: '#ff6b6b' }}>{e.target}</span>
                    {' '}造成{' '}
                    <span style={{ color: '#f44336', fontWeight: 600 }}>
                        {e.value}
                    </span>
                    {' '}点伤害
                    {e.isCrit && (
                        <span style={{ color: '#ff9800', marginLeft: 4 }}>
                            [暴击!]
                        </span>
                    )}
                </>
            )}

            {e.type === 'heal' && (
                <>
                    {' '}恢复{' '}
                    <span style={{ color: '#4CAF50', fontWeight: 600 }}>
                        {e.value}
                    </span>
                    {' '}点生命
                </>
            )}

            {e.type === 'block' && (
                <>
                    {' '}格挡了{' '}
                    <span style={{ color: '#4CAF50', fontWeight: 600 }}>
                        {e.value}
                    </span>
                    {' '}点伤害
                </>
            )}

            {e.type === 'buff' && (
                <>
                    {' '}获得效果（持续{' '}
                    <span style={{ color: '#4CAF50', fontWeight: 700 }}>{e.value}</span>
                    {' '}回合）
                </>
            )}
        </>
    );
}

// 战斗日志模态框
const CombatLogsModal = ({ logs, onClose, onClear }) => {

    const safe = Array.isArray(logs) ? logs : [];

    const normalized = safe
        .filter(Boolean)
        .map((x) => {
            if (typeof x === "string") {
                return {
                    id: `legacy_${Date.now()}_${Math.random()}`,
                    timestamp: Date.now(),
                    characterName: "系统",
                    zoneName: "",
                    enemyName: "",
                    result: "victory",
                    logs: [x],
                    rewards: { gold: 0, exp: 0 },
                    drops: [],

                };
            }
            return {
                ...x,
                logs: Array.isArray(x.logs) ? x.logs : [],
                drops: Array.isArray(x.drops) ? x.drops : [] // ✅ 新增
            };
        });

    return (
        <div style={{
            position: 'fixed',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            background: 'rgba(0,0,0,0.85)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            zIndex: 1000,
            padding: 20
        }} onClick={onClose}>
            <div style={{
                background: 'linear-gradient(135deg, rgba(30,25,20,0.98) 0%, rgba(20,15,12,0.98) 100%)',
                border: '3px solid #c9a227',
                borderRadius: 12,
                padding: 24,
                maxWidth: 800,
                width: '100%',
                maxHeight: '80vh',
                display: 'flex',
                flexDirection: 'column',
                boxShadow: '0 8px 32px rgba(201,162,39,0.3)',
            }} onClick={(e) => e.stopPropagation()}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 }}>
                    <h2 style={{ margin: 0, fontSize: 20, color: '#ffd700' }}>
                        战斗日志
                    </h2>
                    <div style={{ display: 'flex', gap: 8 }}>
                        <Button onClick={onClear} variant="danger">清空日志</Button>
                        <Button onClick={onClose} variant="secondary">✕ 关闭</Button>
                    </div>
                </div>

                <div style={{
                    flex: 1,
                    overflowY: 'auto',
                    background: 'rgba(0,0,0,0.3)',
                    borderRadius: 6,
                    padding: 12
                }}>
                    {logs.length === 0 ? (
                        <div style={{ textAlign: 'center', color: '#666', padding: 40 }}>
                            暂无战斗记录
                        </div>
                    ) : (
                        normalized.map(log => (
                            <div key={log.id} style={{
                                background: log.result === 'victory' ? 'rgba(76,175,80,0.1)' : 'rgba(244,67,54,0.1)',
                                border: `1px solid ${log.result === 'victory' ? '#4CAF50' : '#f44336'}`,
                                borderRadius: 6,
                                padding: 12,
                                marginBottom: 12
                            }}>
                                <div style={{
                                    display: 'flex',
                                    justifyContent: 'space-between',
                                    marginBottom: 8,
                                    paddingBottom: 8,
                                    borderBottom: '1px solid rgba(255,255,255,0.1)'
                                }}>
                                    <div>
                                        <span style={{ color: '#ffd700', fontWeight: 600 }}>
                                            {log.characterName}
                                        </span>
                                        <span style={{ color: '#888', margin: '0 8px' }}>VS</span>
                                        <span style={{ color: '#ff6b6b', fontWeight: 600 }}>
                                            {log.enemyName}
                                        </span>
                                        <span style={{ color: '#888', marginLeft: 8 }}>
                                            @ {log.zoneName}
                                        </span>
                                    </div>
                                    <div style={{
                                        fontSize: 11,
                                        color: log.result === 'victory' ? '#4CAF50' : '#f44336',
                                        fontWeight: 600
                                    }}>
                                        {log.result === 'victory' ? '✓ 胜利' : '✗ 失败'}
                                    </div>
                                </div>

                                <div style={{
                                    maxHeight: 200,
                                    overflowY: 'auto',
                                    fontSize: 11,
                                    color: '#ccc'
                                }}>
                                    {(log.logs || []).map((entry, i) => (
                                        <div key={i} style={{
                                            padding: '4px 0',
                                            borderBottom: i < log.logs.length - 1 ? '1px solid rgba(255,255,255,0.05)' : 'none'
                                        }}>
                                            <span style={{ color: '#888' }}>回合{entry.round}:</span>{' '}
                                            {renderCombatLogLine(entry)}
                                        </div>
                                    ))}
                                </div>

                                {/* 在奖励显示后添加掉落摘要 */}
                                {log.drops && log.drops.length > 0 && (
                                    <div style={{
                                        marginTop: 8,
                                        paddingTop: 8,
                                        borderTop: '1px solid rgba(255,255,255,0.1)',
                                        fontSize: 12
                                    }}>
                                        <span style={{ color: '#ffd700', marginRight: 8 }}>🎁 掉落：</span>
                                        {log.drops.map((drop, idx) => {
                                            const rarityColors = {
                                                white: '#d9d9d9',
                                                green: '#1eff00',
                                                blue: '#0070dd',
                                                purple: '#a335ee',
                                                orange: '#ff8000'
                                            };
                                            const color = rarityColors[drop.rarity] || '#ffd700';
                                            return (
                                                <span key={idx} style={{ marginRight: 12 }}>
                                                <span style={{ color: color, fontWeight: 600 }}>{drop.name}</span>
                                                <span style={{ color: '#666', fontSize: 10, marginLeft: 4 }}>
                                                    ({drop.chance < 1 ? drop.chance.toFixed(2) : drop.chance.toFixed(1)}%)
                                                </span>
                                                </span>
                                            );
                                        })}
                                    </div>
                                )}

                                {log.rewards && (
                                    <div style={{
                                        marginTop: 8,
                                        paddingTop: 8,
                                        borderTop: '1px solid rgba(255,255,255,0.1)',
                                        fontSize: 11,
                                        color: '#ffd700'
                                    }}>
                                        奖励: 🪙{log.rewards.gold} | ⭐{log.rewards.exp}
                                    </div>
                                )}
                            </div>
                        ))
                    )}
                </div>
            </div>
        </div>
    );
};

// 角色详情模态框
const CharacterDetailsModal = ({ characterId, state, onClose, onUnequip, onEditSkills, onViewSkills, onSyncSkills }) => {
    const character = state.characters.find(c => c.id === characterId);

    // 角色被删除/不存在时，直接不渲染（或你也可以 onClose()）
    if (!character) return null;

    const [syncTip, setSyncTip] = useState(null);
    const syncTipTimerRef = useRef(null);

    const showSyncTip = (msg) => {
        setSyncTip(msg);
        if (syncTipTimerRef.current) clearTimeout(syncTipTimerRef.current);
        syncTipTimerRef.current = setTimeout(() => setSyncTip(null), 1500);
    };

    useEffect(() => {
        return () => {
            if (syncTipTimerRef.current) clearTimeout(syncTipTimerRef.current);
        };
    }, []);

    const currentSkills = character.skills || [];
    const levelSkills = learnNewSkills(character);
    const missingSkills = levelSkills.filter(s => !currentSkills.includes(s));
    const canSyncSkills = missingSkills.length > 0;

    const statNames = {
        hp: '生命值',
        mp: '法力值',
        attack: '攻击强度',
        spellPower: '法术强度',
        armor: '护甲',
        magicResist: '魔法抗性',
        haste: '急速',
        critRate: '暴击率',
        critDamage: '暴击伤害',
        mastery: '精通',
        versatility: '全能',
        blockRate: '格挡率',
        blockValue: '格挡值',
        // 新增采集属性
        proficiency: '熟练',
        precision: '精细',
        perception: '感知',
    };

    const setBonuses = getSetBonusesForCharacter(character);
    // ✅ 采集属性（含等级/装备/种族加成），用于属性栏展示
    const gatherStats = calculateGatherStats(character);

    return (
        <div style={{
            position: 'fixed',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            background: 'rgba(0,0,0,0.85)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            zIndex: 1000,
            padding: 20,
            overflowY: 'auto'
        }} onClick={onClose}>
            <div style={{
                background: 'linear-gradient(135deg, rgba(30,25,20,0.98) 0%, rgba(20,15,12,0.98) 100%)',
                border: '3px solid #c9a227',
                borderRadius: 12,
                padding: 24,
                maxWidth: 900,
                width: '100%',
                maxHeight: '90vh',
                overflowY: 'auto',
                boxShadow: '0 8px 32px rgba(201,162,39,0.3)',
            }} onClick={(e) => e.stopPropagation()}>
                <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'start', marginBottom: 20 }}>
                    <div>
                        <h2 style={{ margin: '0 0 8px 0', fontSize: 24, color: '#ffd700' }}>
                            {character.name}
                        </h2>
                        <div style={{ fontSize: 14, color: '#888' }}>
                            Lv.{character.level} {character.race} {CLASSES[character.classId].name}
                        </div>
                    </div>
                    <div style={{ display: 'flex', gap: 8, flexWrap: 'wrap' }}>
                        <Button onClick={onViewSkills} variant="secondary">👁 查看技能</Button>
                        <Button onClick={onEditSkills} variant="secondary">✏️ 编辑技能</Button>
                        <Button
                            onClick={() => {
                                if (!onSyncSkills) return;
                                onSyncSkills();
                                // 简单提示：学会本等级应学会的技能（用于旧角色补齐新技能）
                                showSyncTip(`同步成功：学会 ${missingSkills.length} 个技能`);
                            }}
                            variant="secondary"
                            disabled={!canSyncSkills}
                            title={canSyncSkills ? '学会当前等级应学会的技能（补齐新技能）' : '当前已学会本等级应学会的技能'}
                        >
                            📚 学会本级技能
                        </Button>
                        <Button onClick={onClose} variant="secondary">✕ 关闭</Button>
                    </div>
                </div>

                {syncTip && (
                    <div style={{
                        marginTop: 10,
                        background: 'rgba(0,0,0,0.35)',
                        border: '1px solid rgba(201,162,39,0.35)',
                        color: '#f3e6b3',
                        padding: '8px 12px',
                        borderRadius: 8,
                        fontSize: 13,
                    }}>
                        ✅ {syncTip}
                    </div>
                )}

                <div style={{ display: 'grid', gridTemplateColumns: '1fr 2fr', gap: 20 }}>
                    {/* 左侧：属性 */}
                    <div>
                        <h3 style={{ fontSize: 16, color: '#c9a227', marginBottom: 12 }}>角色属性</h3>
                        <div style={{
                            background: 'rgba(0,0,0,0.3)',
                            borderRadius: 6,
                            padding: 12,
                            border: '1px solid #4a3c2a'
                        }}>
                            {Object.entries(statNames).map(([stat, name]) => (
                                <div key={stat} style={{
                                    display: 'flex',
                                    justifyContent: 'space-between',
                                    padding: '6px 0',
                                    borderBottom: '1px solid rgba(255,255,255,0.05)',
                                    fontSize: 12
                                }}>
                                    <span style={{ color: '#aaa' }}>{name}</span>
                                    <span style={{ color: '#ffd700', fontWeight: 600 }}>
                                        {(() => {
                                            const isGatherStat = stat === 'proficiency' || stat === 'precision' || stat === 'perception';
                                            const rawValue = isGatherStat
                                                ? (gatherStats?.[stat] ?? 0)
                                                : (character.stats?.[stat] ?? 0);

                                            if (stat === 'critRate' || stat === 'blockRate') {
                                                return `${Number(rawValue || 0).toFixed(1)}%`;
                                            }
                                            if (stat === 'critDamage') {
                                                return `${Math.round((Number(rawValue) || 0) * 100)}%`;
                                            }
                                            return Math.floor(Number(rawValue) || 0);
                                        })()}
                                    </span>
                                </div>
                            ))}
                        </div>
                    </div>

                    {/* 右侧：装备 */}
                    <div>
                        <h3 style={{ fontSize: 16, color: '#c9a227', marginBottom: 12 }}>装备</h3>
                        <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: 8 }}>
                            {Object.entries(EQUIPMENT_SLOTS).map(([slot, slotInfo]) => {
                                const equipped = character.equipment[slot];
                                return (
                                    <div
                                        key={slot}
                                        style={{
                                            background: equipped ? 'rgba(201,162,39,0.15)' : 'rgba(0,0,0,0.3)',
                                            border: `2px solid ${equipped ? '#c9a227' : '#4a3c2a'}`,
                                            borderRadius: 6,
                                            padding: 12,
                                            minHeight: 80,
                                            position: 'relative'
                                        }}
                                    >
                                        <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
                                            {equipped ? (
                                                <ItemIcon item={equipped} size={18} />
                                            ) : (
                                                <span>{slotInfo.icon}</span>
                                            )}
                                            <span>{slotInfo.name}</span>
                                        </div>


                                        {equipped ? (
                                            <>
                                                <div style={{
                                                    fontSize: 12,
                                                    color: equipped.qualityColor,
                                                    fontWeight: 600,
                                                    marginBottom: 6
                                                }}>
                                                    {equipped.name}
                                                </div>

                                                <div style={{ fontSize: 10, color: '#aaa', marginBottom: 8 }}>
                                                    {Object.entries(equipped.stats).map(([stat, value]) => (
                                                        <div key={stat}>
                                                            {statNames[stat] || stat}: +{formatItemStatValue(stat, value)}
                                                        </div>
                                                    ))}
                                                </div>

                                                <Button
                                                    onClick={() => onUnequip(character.id, slot)}
                                                    variant="danger"
                                                    style={{ padding: '4px 8px', fontSize: 10, width: '100%' }}
                                                >
                                                    卸下
                                                </Button>
                                            </>
                                        ) : (
                                            <div style={{
                                                fontSize: 24,
                                                color: '#333',
                                                textAlign: 'center',
                                                paddingTop: 8
                                            }}>
                                                ∅
                                            </div>
                                        )}
                                    </div>
                                );
                            })}
                        </div>

                        {/* 套装效果 */}
                        {setBonuses.length > 0 && (
                            <div style={{
                                marginTop: 14,
                                padding: 12,
                                borderRadius: 8,
                                background: 'rgba(0,0,0,0.25)',
                                border: '1px solid rgba(201,162,39,0.25)'
                            }}>
                                <div style={{ fontSize: 14, fontWeight: 800, color: '#ffd700', marginBottom: 8 }}>
                                    套装效果
                                </div>

                                <div style={{ display: 'flex', flexDirection: 'column', gap: 10 }}>
                                    {setBonuses.map(set => (
                                        <div key={set.setId} style={{
                                            padding: 10,
                                            borderRadius: 8,
                                            background: 'rgba(0,0,0,0.25)',
                                            border: '1px solid rgba(201,162,39,0.18)'
                                        }}>
                                            <div style={{
                                                display: 'flex',
                                                justifyContent: 'space-between',
                                                alignItems: 'baseline',
                                                marginBottom: 6
                                            }}>
                                                <div style={{ fontSize: 13, fontWeight: 800, color: '#c9a227' }}>
                                                    {set.name}
                                                </div>
                                                <div style={{ fontSize: 11, color: '#aaa' }}>
                                                    已装备 {set.count} 件
                                                </div>
                                            </div>

                                            <div style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
                                                {set.activated.map((t, idx) => (
                                                    <div key={idx} style={{ fontSize: 12, color: '#ddd' }}>
                                                        ✅ {t.count} 件：{(() => {
                                                        const parts = [];
                                                        const bt = formatBonusText(t.bonus);
                                                        if (bt) parts.push(bt);

                                                        const effects = Array.isArray(t?.procEffects) ? t.procEffects : [];
                                                        effects.forEach(se => {
                                                            if (!se || se.type !== 'proc_stat') return;
                                                            if (se.trigger !== 'turn_start') return;

                                                            const chance = Math.max(0, Math.min(1, Number(se.chance) || 0));
                                                            const pct = Math.round(chance * 100);
                                                            const bonusText = formatProcStatBonusText(se.stats || {});
                                                            parts.push(`🎲 每回合${pct}%：${bonusText || '触发增益'}`);
                                                        });

                                                        return parts.join('；');
                                                    })()}
                                                    </div>
                                                ))}
                                            </div>
                                        </div>
                                    ))}
                                </div>
                            </div>
                        )}
                    </div>
                </div>
            </div>
        </div>
    );
};





// 物品详情模态框
const ItemDetailsModal = ({ item, onClose, onEquip, characters, state , dispatch }) => {
    const [selectedCharId, setSelectedCharId] = useState('');

    const statNames = {
        hp: '生命值',
        mp: '法力值',
        attack: '攻击强度',
        spellPower: '法术强度',
        armor: '护甲',
        magicResist: '魔法抗性',
        haste: '急速',
        critRate: '暴击率',
        critDamage: '暴击伤害',
        mastery: '精通',
        versatility: '全能',
        blockRate: '格挡率',
        blockValue: '格挡值',
        expBonus: '经验值增幅',
        proficiency: '熟练',
        precision: '精细',
        perception: '感知',
    };

    return (
        <div style={{
            position: 'fixed',
            top: 0,
            left: 0,
            right: 0,
            bottom: 0,
            background: 'rgba(0,0,0,0.85)',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            zIndex: 1000,
            padding: 20
        }} onClick={onClose}>
            <div style={{
                background: 'linear-gradient(135deg, rgba(30,25,20,0.98) 0%, rgba(20,15,12,0.98) 100%)',
                border: `3px solid ${item.qualityColor || '#4a3c2a'}`,
                borderRadius: 12,
                padding: 24,
                maxWidth: 400,
                width: '100%',
                boxShadow: `0 8px 32px ${item.qualityColor}44`,
            }} onClick={(e) => e.stopPropagation()}>
                <div style={{ textAlign: 'center', marginBottom: 20 }}>
                    <div style={{ fontSize: 48, marginBottom: 12 }}>
                        <ItemIcon item={item} size={32} />
                    </div>
                    <h2 style={{
                        margin: '0 0 8px 0',
                        fontSize: 20,
                        color: item.qualityColor,
                        textShadow: '2px 2px 4px rgba(0,0,0,0.8)'
                    }}>
                        {item.name}
                    </h2>
                    <div style={{ fontSize: 12, color: '#888' }}>
                        {EQUIPMENT_SLOTS[item.slot]?.name} · 等级 {item.currentLevel ?? item.level ?? 0} · {item.quality}
                    </div>
                </div>

                <div style={{
                    background: 'rgba(0,0,0,0.3)',
                    borderRadius: 8,
                    padding: 16,
                    marginBottom: 20
                }}>
                    <h3 style={{ fontSize: 14, color: '#c9a227', marginBottom: 12 }}>属性</h3>
                    {Object.entries(item.stats).map(([stat, value]) => (
                        <div
                            key={stat}
                            style={{
                                display: 'flex',
                                justifyContent: 'space-between',
                                padding: '6px 0',
                                borderBottom: '1px solid rgba(255,255,255,0.05)',
                                fontSize: 12
                            }}
                        >
                            <span style={{ color: '#aaa' }}>{statNames[stat] || stat}</span>
                            <span style={{ color: '#4CAF50', fontWeight: 600 }}>
                                +{formatItemStatValue(stat, value)}
                            </span>
                        </div>
                    ))}
                </div>

                {/* 特殊效果显示 */}
                {(() => {
                  const effects = getEquipmentSpecialEffectList(item);
                  if (effects.length === 0) return null;

                  const fmtPct = (v) => `${Math.round((Number(v) || 0) * 100)}%`;

                  return (
                    <div style={{
                      background: 'rgba(255, 152, 0, 0.1)',
                      border: '1px solid rgba(255, 152, 0, 0.3)',
                      borderRadius: 8,
                      padding: 16,
                      marginBottom: 20
                    }}>
                      <h3 style={{ fontSize: 14, color: '#ff9800', marginBottom: 12 }}>⚡ 特殊效果</h3>

                      {effects.map((se, idx) => {
                        if (!se || typeof se !== 'object') return null;

                        const type = se.type;
                        const chance = Math.max(0, Math.min(1, Number(se.chance) || 0));
                        const trigger = se.trigger || 'turn_start';

                        return (
                          <div key={idx} style={{ marginTop: idx ? 12 : 0 }}>

                            {/* skill_slot_buff：技能格强化 */}
                            {type === 'skill_slot_buff' && (() => {
                              const slots = Array.isArray(se.slots)
                                ? se.slots
                                : (Number.isFinite(Number(se.slot)) ? [Number(se.slot)] : []);
                              const slotText = slots.length ? slots.map(s => s + 1).join('、') : '？';

                              const atk = Number(se.attackBonus) || 0;
                              const sp = Number(se.spellPowerBonus) || 0;

                              return (
                                <div style={{ fontSize: 12, color: '#ffb74d', lineHeight: 1.6 }}>
                                  在第 <span style={{ color: '#ffd700', fontWeight: 600 }}>{slotText}</span> 技能格释放技能时：
                                  {atk !== 0 && (
                                    <div style={{ marginTop: 8, color: '#fff' }}>
                                      • 攻击强度 <span style={{ color: '#4CAF50', fontWeight: 600 }}>+{formatItemStatValue('attack', atk)}</span>
                                    </div>
                                  )}
                                  {sp !== 0 && (
                                    <div style={{ marginTop: 8, color: '#fff' }}>
                                      • 法术强度 <span style={{ color: '#4CAF50', fontWeight: 600 }}>+{formatItemStatValue('spellPower', sp)}</span>
                                    </div>
                                  )}
                                  <div style={{
                                    marginTop: 12,
                                    padding: '8px 12px',
                                    background: 'rgba(255,215,0,0.1)',
                                    borderRadius: 6,
                                    border: '1px dashed rgba(255,215,0,0.3)',
                                    fontSize: 11,
                                    color: '#c9a227'
                                  }}>
                                    💡 提示：该特效会随装备等级线性增强（lv0=1x, lv100=2x）
                                  </div>
                                </div>
                              );
                            })()}

                            {/* skill_slot_shield：技能格护盾 */}
                            {type === 'skill_slot_shield' && (() => {
                              const slots = Array.isArray(se.slots)
                                ? se.slots
                                : (Number.isFinite(Number(se.slot)) ? [Number(se.slot)] : []);
                              const slotText = slots.length ? slots.map(s => s + 1).join('、') : '？';

                              const basedOn = String(se.basedOn || 'maxHp');
                              const mult = Number(se.amountMult ?? 0);
                              const flat = Number(se.amountFlat ?? 0);
                              const dur = Math.max(1, Math.floor(Number(se.duration) || 1));

                              const basedOnText =
                                basedOn === 'spellPower' ? '法术强度'
                                : basedOn === 'attack' ? '攻击强度'
                                : '最大生命';

                              return (
                                <div style={{ fontSize: 12, color: '#ffb74d', lineHeight: 1.6 }}>
                                  <div style={{ marginBottom: 8, color: '#fff' }}>
                                    在第 <span style={{ color: '#ffd700', fontWeight: 600 }}>{slotText}</span> 技能格释放技能时获得护盾（吸收伤害）：
                                  </div>
                                  <div style={{ marginTop: 8, color: '#fff' }}>
                                    • 护盾：<span style={{ color: '#ffd700', fontWeight: 600 }}>{se.name || '护盾'}</span>
                                  </div>
                                  <div style={{ marginTop: 8, color: '#fff' }}>
                                    • 计算：{basedOnText} × <span style={{ color: '#ffd700', fontWeight: 600 }}>{mult}</span>{flat ? ` + ${Math.floor(flat)}` : ''}
                                  </div>
                                  <div style={{ marginTop: 8, color: '#fff' }}>
                                    • 持续：<span style={{ color: '#ffd700', fontWeight: 600 }}>{dur}</span> 回合{se.scaleWithLevel ? '（随装备等级增强）' : ''}
                                  </div>
                                </div>
                              );
                            })()}

                            {/* heal_cast_shield：治疗施法护盾（例如：甲虫胸针） */}
                            {type === 'heal_cast_shield' && (() => {
                              const pct = Number(se.shieldPct) || 0;
                              const flat = Math.floor(Number(se.shieldFlat) || 0);
                              const dur = Math.max(1, Math.floor(Number(se.duration) || 1));
                              const capPct = Number(se.maxPctOfTargetMaxHp) || 0;
                              const chance = (se.chance == null) ? 1 : Math.max(0, Math.min(1, Number(se.chance) || 0));

                              return (
                                <div style={{ fontSize: 12, color: '#ffb74d', lineHeight: 1.6 }}>
                                  <div style={{ marginBottom: 8, color: '#fff' }}>
                                    施放治疗技能并产生有效治疗时，为目标附加护盾（吸收伤害）：
                                  </div>
                                  <div style={{ marginTop: 8, color: '#fff' }}>
                                    • 护盾：<span style={{ color: '#ffd700', fontWeight: 600 }}>{se.name || '护盾'}</span>
                                  </div>
                                  <div style={{ marginTop: 8, color: '#fff' }}>
                                    • 吸收量：有效治疗 × <span style={{ color: '#ffd700', fontWeight: 600 }}>{fmtPct(pct)}</span>{flat ? ` + ${flat}` : ''}{se.scaleWithLevel ? '（随装备等级增强）' : ''}
                                  </div>
                                  <div style={{ marginTop: 8, color: '#fff' }}>
                                    • 持续：<span style={{ color: '#ffd700', fontWeight: 600 }}>{dur}</span> 回合
                                  </div>
                                  {capPct > 0 && (
                                    <div style={{ marginTop: 8, color: '#fff' }}>
                                      • 上限：目标最大生命的 <span style={{ color: '#ffd700', fontWeight: 600 }}>{fmtPct(capPct)}</span>
                                    </div>
                                  )}
                                  {chance < 1 && (
                                    <div style={{ marginTop: 8, color: '#fff' }}>
                                      • 触发率：<span style={{ color: '#ffd700', fontWeight: 600 }}>{(chance * 100).toFixed(0)}%</span>
                                    </div>
                                  )}
                                </div>
                              );
                            })()}

                            {/* basic_attack_repeat */}

{type === 'basic_attack_repeat' && (
                              <div style={{ fontSize: 12, color: '#ffb74d', lineHeight: 1.6 }}>
                                <div style={{ marginBottom: 8, color: '#fff' }}>
                                  使用普通攻击后，有 <span style={{ color: '#ffd700', fontWeight: 600 }}>{(chance * 100).toFixed(0)}%</span> 概率再次发动一次普通攻击
                                </div>
                                <div style={{
                                  marginTop: 12,
                                  padding: '8px 12px',
                                  background: 'rgba(255,215,0,0.1)',
                                  borderRadius: 6,
                                  border: '1px dashed rgba(255,215,0,0.3)',
                                  fontSize: 11,
                                  color: '#c9a227'
                                }}>
                                  💡 提示：连击伤害与普通攻击相同，可触发“质朴”等普攻相关天赋
                                </div>
                              </div>
                            )}

                            {/* proc_stat */}
                            {type === 'proc_stat' && (
                              <div style={{ fontSize: 12, color: '#ffb74d', lineHeight: 1.6 }}>
                                <div style={{ marginBottom: 8, color: '#fff' }}>
                                  {(trigger === 'turn_start') ? '每回合开始' : '触发时'}有 <span style={{ color: '#ffd700', fontWeight: 600 }}>{(chance * 100).toFixed(0)}%</span> 概率获得以下增益（仅本回合）：
                                </div>

                                {Object.entries((se.stats && typeof se.stats === 'object') ? se.stats : {}).map(([stat, value]) => (
                                  <div key={stat} style={{ marginTop: 8, color: '#fff' }}>
                                    • {statNames[stat] || stat}{' '}
                                    <span style={{ color: '#4CAF50', fontWeight: 600 }}>+{formatItemStatValue(stat, value)}</span>
                                  </div>
                                ))}

                                {se.scaleWithLevel && (
                                  <div style={{
                                    marginTop: 12,
                                    padding: '8px 12px',
                                    background: 'rgba(255,215,0,0.1)',
                                    borderRadius: 6,
                                    border: '1px dashed rgba(255,215,0,0.3)',
                                    fontSize: 11,
                                    color: '#c9a227'
                                  }}>
                                    💡 提示：该特效会随装备等级提升而增强（lv0=1x, lv100=2x）
                                  </div>
                                )}
                              </div>
                            )}

                            {/* boss_team_aura */}
                            {type === 'boss_team_aura' && (
                              <div style={{ fontSize: 12, color: '#ffb74d', lineHeight: 1.6 }}>
                                <div style={{ marginBottom: 8, color: '#fff' }}>
                                  👥 仅BOSS战生效：为队伍中所有成员提供以下属性加成（不叠加）：
                                </div>

                                {Object.entries((se.stats && typeof se.stats === 'object') ? se.stats : {}).map(([stat, value]) => (
                                  <div key={stat} style={{ marginTop: 8, color: '#fff' }}>
                                    • {statNames[stat] || stat}{' '}
                                    <span style={{ color: '#4CAF50', fontWeight: 600 }}>+{formatItemStatValue(stat, value)}</span>
                                  </div>
                                ))}

                                <div style={{
                                  marginTop: 12,
                                  padding: '8px 12px',
                                  background: 'rgba(255,215,0,0.1)',
                                  borderRadius: 6,
                                  border: '1px dashed rgba(255,215,0,0.3)',
                                  fontSize: 11,
                                  color: '#c9a227'
                                }}>
                                  💡 提示：同名团队光环不会叠加（团队内只生效一次）
                                </div>
                              </div>
                            )}

                            {/* proc_damage */}
                            {type === 'proc_damage' && (
                              <div style={{ fontSize: 12, color: '#ffb74d', lineHeight: 1.6 }}>
                                <div style={{ marginBottom: 8, color: '#fff' }}>
                                  {(trigger === 'turn_start') ? '每回合开始' : '触发时'}有 <span style={{ color: '#ffd700', fontWeight: 600 }}>{(chance * 100).toFixed(0)}%</span> 概率触发
                                  <span style={{ color: '#ffd700', fontWeight: 600 }}> {se.name || '额外伤害'} </span>：
                                </div>
                                <div style={{ marginTop: 8, color: '#fff' }}>
                                  • 伤害：{Number(se.damageMult) ? `${Number(se.damageMult)}×` : ''}{se.basedOn === 'spellPower' ? '法术强度' : '攻击强度'}{Number(se.damageFlat) ? ` + ${Math.floor(Number(se.damageFlat) || 0)}` : ''}（{getSchoolCn(se.school)}）
                                </div>
                              </div>
                            )}

                            {/* ignore_defense */}
                            {type === 'ignore_defense' && (
                              <div style={{ fontSize: 12, color: '#ffb74d', lineHeight: 1.6 }}>
                                <div style={{ color: '#fff' }}>
                                  🛡️ 穿甲：无视敌人 <span style={{ color: '#ffd700', fontWeight: 600 }}>{fmtPct(se.pct ?? se.ignorePct ?? se.value)}</span> 防御
                                </div>
                              </div>
                            )}

                            {/* thunderfury：按你当前数据字段展示（不再 NaN） */}
                            {type === 'thunderfury' && (() => {
                              const damageMult = Number(se.damageMult) || 1.2;
                              const selfDamageTakenMult = Number(se.selfDamageTakenMult) || 0.8;
                              const selfBuffDuration = Math.max(1, Math.floor(Number(se.selfBuffDuration) || 2));
                              const reductionPct = Math.round((1 - selfDamageTakenMult) * 100);

                              return (
                                <div style={{ fontSize: 12, color: '#ffb74d', lineHeight: 1.6 }}>
                                  <div style={{ marginBottom: 8, color: '#fff' }}>
                                    每回合开始有 <span style={{ color: '#ffd700', fontWeight: 600 }}>{(chance * 100).toFixed(0)}%</span> 概率释放一道闪电链：
                                  </div>
                                  <div style={{ marginTop: 8, color: '#fff' }}>
                                    • 对所有敌人造成 <span style={{ color: '#ffd700', fontWeight: 600 }}>{damageMult.toFixed(1)}倍攻击强度</span> 的自然伤害
                                  </div>
                                  <div style={{ marginTop: 8, color: '#fff' }}>
                                    • 并使自身受到的所有伤害降低 <span style={{ color: '#ffd700', fontWeight: 600 }}>{reductionPct}%</span> ，持续 <span style={{ color: '#ffd700', fontWeight: 600 }}>{selfBuffDuration}</span> 回合
                                  </div>
                                  <div style={{ marginTop: 12, fontSize: 11, color: '#c9a227' }}>
                                    💡 说明：对BOSS战的小怪也有效
                                  </div>
                                </div>
                              );
                            })()}

                            {/* map_slayer */}
                            {type === 'map_slayer' && (
                              <div style={{ fontSize: 12, color: '#ffb74d', lineHeight: 1.6 }}>
                                <div style={{ marginBottom: 8, color: '#fff' }}>
                                  地图战斗中造成的伤害提高 <span style={{ color: '#ffd700', fontWeight: 600 }}>{fmtPct(se.bonusDamageVsMap)}</span>
                                </div>
                              </div>
                            )}

                            {/* fallback */}
                            {![ 'skill_slot_buff','skill_slot_shield','heal_cast_shield','basic_attack_repeat','proc_stat','boss_team_aura','proc_damage','ignore_defense','thunderfury','map_slayer' ].includes(type) && (
                              <div style={{ fontSize: 12, color: '#aaa' }}>
                                ⚡ 特效：{String(type || 'unknown')}
                              </div>
                            )}

                          </div>
                        );
                      })}
                    </div>
                  );
                })()}


                <div style={{ marginBottom: 12 }}>
                  <div style={{ fontSize: 12, color: '#aaa', marginBottom: 6 }}>选择要装备的角色</div>
                  <select
                    value={selectedCharId}
                    onChange={(e) => setSelectedCharId(e.target.value)}
                    style={{
                      width: '100%',
                      padding: '10px 12px',
                      borderRadius: 8,
                      border: '1px solid rgba(255,255,255,0.18)',
                      background: 'rgba(0,0,0,0.35)',
                      color: '#eee',
                      outline: 'none',
                      fontSize: 12,
                    }}
                  >
                        <option value="">选择角色...</option>
                        {characters.map(char => (
                            <option key={char.id} value={char.id}>
                                {char.name} (Lv.{char.level})
                            </option>
                        ))}
                  </select>
                </div>

                <div style={{ display: 'flex', gap: 12 }}>
                    {item.id === 'REBIRTH_INVITATION' && (
                        <Button
                            variant="danger"
                            onClick={() => {
                                dispatch({ type: 'USE_ITEM', payload: { itemInstanceId: item.instanceId || item.id } });
                                onClose();
                            }}
                            style={{ flex: 1 }}
                        >
                            🌀 使用邀请函
                        </Button>
                    )}
                    <Button
                        onClick={() => {
                            if (selectedCharId) {
                                onEquip(selectedCharId, item.instanceId || item.id);
                                onClose();
                            }
                        }}
                        disabled={!selectedCharId}
                        style={{ flex: 1 }}
                    >
                        装备
                    </Button>
                    {(() => {
                        const getLevel = (eq) => (eq?.currentLevel ?? eq?.level ?? 0);
                        const isMatA = item.id === 'EQ_041' && getLevel(item) >= 100;
                        const isMatB = item.id === 'EQ_042' && getLevel(item) >= 100;

                        const hasOther =
                            isMatA
                                ? state.inventory.some(i => i?.type === 'equipment' && i.id === 'EQ_042' && getLevel(i) >= 100)
                                : isMatB
                                    ? state.inventory.some(i => i?.type === 'equipment' && i.id === 'EQ_041' && getLevel(i) >= 100)
                                    : false;

                        if (!(hasOther && (isMatA || isMatB))) return null;

                        return (
                            <Button
                                onClick={() => {
                                    if (window.confirm('消耗【反击者桑萨斯 Lv100】与【保护者加萨斯 Lv100】合成【鞭笞者苏萨斯 Lv0】？')) {
                                        dispatch({ type: 'SYNTHESIZE_EQ_044' });
                                        onClose();
                                    }
                                }}
                                style={{ flex: 1 }}
                            >
                                ⚗️ 苏萨斯
                            </Button>
                        );
                    })()}
                    <Button
                        variant="danger"
                        onClick={() => {
                            if (window.confirm(`确定要丢弃 ${item.name} 吗？`)) {
                                dispatch({ type: 'USE_ITEM', payload: { itemInstanceId: item.instanceId || item.id } });
                                onClose();
                            }
                        }}
                    >
                        🗑️ 丢弃
                    </Button>
                    <Button onClick={onClose} variant="secondary" style={{ flex: 1 }}>
                        关闭
                    </Button>
                </div>
            </div>
        </div>
    );
};


